        param($ctrl, $r)
        if ($ctrl.Width -le 0 -or $ctrl.Height -le 0) { return }
        $D = $r * 2
        $p = New-Object System.Drawing.Drawing2D.GraphicsPath
        $p.AddArc(0, 0, $D, $D, 180, 90)
        $p.AddArc($ctrl.Width - $D, 0, $D, $D, 270, 90)
        $p.AddArc($ctrl.Width - $D, $ctrl.Height - $D, $D, $D, 0, 90)
